import{_ as t,o as i,c as e,ag as s}from"./chunks/framework.gU7RhlGX.js";const c=JSON.parse('{"title":"frontend-design","description":"","frontmatter":{},"headers":[],"relativePath":"skills/front-end/frontend-design.md","filePath":"skills/front-end/frontend-design.md","lastUpdated":1776422487000}'),n={name:"skills/front-end/frontend-design.md"};function o(l,a,r,h,d,p){return i(),e("div",null,[...a[0]||(a[0]=[s('<h1 id="frontend-design" tabindex="-1">frontend-design <a class="header-anchor" href="#frontend-design" aria-label="Permalink to &quot;frontend-design&quot;">​</a></h1><p><code>frontend-design</code> 是 Anthropic 官方推出的 AI Agent Skill，旨在帮助 AI 开发具有<strong>高辨识度、生产级质量</strong>的前端界面。它超越了通用的“AI 审美”，通过明确的设计思维和美美学指南，让 AI 能够创作出富有创意且细节考究的 Web UI。</p><hr><h2 id="🚀-快速开始" tabindex="-1">🚀 快速开始 <a class="header-anchor" href="#🚀-快速开始" aria-label="Permalink to &quot;🚀 快速开始&quot;">​</a></h2><h3 id="安装方式" tabindex="-1">安装方式 <a class="header-anchor" href="#安装方式" aria-label="Permalink to &quot;安装方式&quot;">​</a></h3><p>在你的项目终端中运行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> frontend-design</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><em>注：该 Skill 兼容 Claude Code 等支持 Skill 系统的人工智能辅助工具。</em></p><hr><h2 id="🎨-设计哲学" tabindex="-1">🎨 设计哲学 <a class="header-anchor" href="#🎨-设计哲学" aria-label="Permalink to &quot;🎨 设计哲学&quot;">​</a></h2><p>该 Skill 引导 AI 避免平庸的“AI 风格”，并遵循以下设计逻辑：</p><ol><li><strong>明确调性</strong>：在编码前确定极端风格（如：极致极简、复古未来感、高级精致、报刊杂志风、粗犷主义等）。</li><li><strong>独特性</strong>：寻找让界面“令人难忘”的记忆点。</li><li><strong>工程化</strong>：实现真正可运行、具备生产环境质量的代码。</li></ol><hr><h2 id="📐-审美指南" tabindex="-1">📐 审美指南 <a class="header-anchor" href="#📐-审美指南" aria-label="Permalink to &quot;📐 审美指南&quot;">​</a></h2><h3 id="_1-字体排版-typography" tabindex="-1">1. 字体排版 (Typography) <a class="header-anchor" href="#_1-字体排版-typography" aria-label="Permalink to &quot;1. 字体排版 (Typography)&quot;">​</a></h3><ul><li><strong>拒绝通用</strong>：避免使用 Arial、Inter 或 Roboto 等常见系统字体。</li><li><strong>独特搭配</strong>：使用极具个性的显示字体（Display Font）搭配精致的正文文字。</li></ul><h3 id="_2-颜色与主题-color-theme" tabindex="-1">2. 颜色与主题 (Color &amp; Theme) <a class="header-anchor" href="#_2-颜色与主题-color-theme" aria-label="Permalink to &quot;2. 颜色与主题 (Color &amp; Theme)&quot;">​</a></h3><ul><li><strong>强一致性</strong>：使用 CSS 变量确保色调统一。</li><li><strong>鲜明对比</strong>：倾向于使用具有强烈视觉冲击力的主色调配合精准的强调色。</li></ul><h3 id="_3-动态交互-motion" tabindex="-1">3. 动态交互 (Motion) <a class="header-anchor" href="#_3-动态交互-motion" aria-label="Permalink to &quot;3. 动态交互 (Motion)&quot;">​</a></h3><ul><li><strong>CSS 优先</strong>：优先使用 CSS 动画实现丝滑的揭示效果。</li><li><strong>高光时刻</strong>：通过交错加载（staggered reveals）和令人惊喜的悬停状态提升用户愉悦感。</li></ul><h3 id="_4-空间布局-spatial-composition" tabindex="-1">4. 空间布局 (Spatial Composition) <a class="header-anchor" href="#_4-空间布局-spatial-composition" aria-label="Permalink to &quot;4. 空间布局 (Spatial Composition)&quot;">​</a></h3><ul><li><strong>打破常规</strong>：尝试不对称布局、元素重叠、对角线流向或网格留白，创造节奏感。</li></ul><h3 id="_5-视觉细节-visual-details" tabindex="-1">5. 视觉细节 (Visual Details) <a class="header-anchor" href="#_5-视觉细节-visual-details" aria-label="Permalink to &quot;5. 视觉细节 (Visual Details)&quot;">​</a></h3><ul><li><strong>深度感</strong>：使用梯度网格（Gradient Mesh）、噪点纹理、几何图案或磨砂玻璃效果替代纯色背景。</li></ul><hr><h2 id="🛠️-使用场景" tabindex="-1">🛠️ 使用场景 <a class="header-anchor" href="#🛠️-使用场景" aria-label="Permalink to &quot;🛠️ 使用场景&quot;">​</a></h2><ul><li><strong>网页/组件开发</strong>：构建 Landing Page、仪表盘、复杂的 React/Vue 组件。</li><li><strong>UI 美化</strong>：对现有的 Web 界面进行重构或视觉升级。</li><li><strong>创意演示</strong>：制作海报级布局、数据可视化或互动演示。</li></ul><hr><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>切记</strong>：<code>frontend-design</code> 的核心是<strong>意图 (Intentionality)</strong>。无论是极致的简洁还是华丽的繁复，每一行代码和样式都应为整体视觉愿景服务。</p></div><hr><p><strong>官方仓库</strong>：<a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">anthropics/skills</a></p>',31)])])}const u=t(n,[["render",o]]);export{c as __pageData,u as default};
